return [
  {
    json: {
      client_name: "Aisyah Binti Rahman",
      client_email: "aisyahrahman@email.com",
      policy_number: "POL-INS-2026-00981",
      claim_reference_number: "CLM-2026-00452",
      doctor_name: "Dr. Amir Hakim",
      doctor_review_decision: "Approved",
      doctor_review_date: "2026-05-18",
      doctor_review_notes: "Medical documents reviewed and accepted for claim processing.",
      hospital_or_clinic: "KPJ Specialist Hospital",
      treatment_date: "2026-05-05",
      medical_leave_duration: "6 days",
      xray_review_status: "Not Applicable",
      support_email: "support@company.com",
      agent_email: "agent@company.com"
    }
  }
];

const input = $json;

const clientName = input.client_name || "";
const clientEmail = input.client_email || "";
const policyNumber = input.policy_number || "";
const claimRef = input.claim_reference_number || "";
const doctorName = input.doctor_name || "";
const decision = input.doctor_review_decision || "";
const reviewDate = input.doctor_review_date || "";
const notes = input.doctor_review_notes || "";
const hospital = input.hospital_or_clinic || "";
const treatmentDate = input.treatment_date || "";
const medicalLeaveDuration = input.medical_leave_duration || "";
const xrayStatus = input.xray_review_status || "Unclear";
const supportEmail = input.support_email || "support@company.com";
const agentEmail = input.agent_email || "agent@company.com";

const supportSubject = `Insurance Doctor Review Approved - ${claimRef}`;

const clientNotificationSubjectDraft = `Medical Document Review Completed - ${claimRef}`;

const clientNotificationBodyDraft = `Dear ${clientName},

We would like to inform you that the medical document review for your insurance claim has been completed.

Claim Reference Number:
${claimRef}

The submitted medical documents have been reviewed and approved by the insurance doctor.

Your claim will proceed to the next insurance processing stage according to company procedures.

Please note that this notification does not confirm payment completion. Any further updates will be provided by the relevant insurance team.

Thank you.

Support Team`;

const supportBody = `Dear Support Team,

The insurance doctor has approved the medical document review for the following insurance claim.

Claim Reference Number:
${claimRef}

Client Name:
${clientName}

Client Email:
${clientEmail}

Policy Number:
${policyNumber}

Doctor Name:
${doctorName}

Doctor Review Decision:
${decision}

Doctor Review Date:
${reviewDate}

Doctor Review Notes:
${notes}

Hospital / Clinic:
${hospital}

Treatment Date:
${treatmentDate}

Medical Leave Duration:
${medicalLeaveDuration}

X-ray Review Status:
${xrayStatus}

Next Action:
Please create and send a new notification to the client informing them that the medical document review has been completed and approved by the insurance doctor.

Client Notification Subject Draft:
${clientNotificationSubjectDraft}

Client Notification Body Draft:
${clientNotificationBodyDraft}

Thank you.`;

const agentSubject = `Medical Review Approved by Insurance Doctor - ${claimRef}`;

const agentBody = `Dear Insurance Agent,

The insurance doctor has approved the medical document review for this claim.

Claim Reference Number:
${claimRef}

Client Name:
${clientName}

Policy Number:
${policyNumber}

Doctor Name:
${doctorName}

Doctor Review Decision:
${decision}

Doctor Review Date:
${reviewDate}

Doctor Review Notes:
${notes}

Hospital / Clinic:
${hospital}

Treatment Date:
${treatmentDate}

Medical Leave Duration:
${medicalLeaveDuration}

X-ray Review Status:
${xrayStatus}

The claim may proceed to the next insurance processing stage according to company procedure.

Thank you.`;

const auditNote = `Medical document review for claim ${claimRef} was approved by ${doctorName} on ${reviewDate}. Support and agent notifications were generated. Support is responsible for sending a new notification to the client.`;

return [
  {
    json: {
      doctor_review_approval_summary: {
        client_name: clientName,
        client_email: clientEmail,
        policy_number: policyNumber,
        claim_reference_number: claimRef,
        doctor_name: doctorName,
        doctor_review_decision: decision,
        doctor_review_date: reviewDate,
        doctor_review_notes: notes,
        hospital_or_clinic: hospital,
        treatment_date: treatmentDate,
        medical_leave_duration: medicalLeaveDuration,
        xray_review_status: xrayStatus
      },
      support_email: supportEmail,
      agent_email: agentEmail,
      support_notification_subject: supportSubject,
      support_notification_body: supportBody,
      agent_notification_subject: agentSubject,
      agent_notification_body: agentBody,
      client_notification_subject_draft: clientNotificationSubjectDraft,
      client_notification_body_draft: clientNotificationBodyDraft,
      next_action: "Support team to send new notification to client.",
      notification_status: "Ready to Notify Support and Agent",
      audit_note: auditNote
    }
  }
];

return [
  {
    json: {
      claim_reference_number: $json.claim_reference_number || "",
      doctor_review_decision: $json.doctor_review_decision || "Unclear",
      doctor_review_notes: $json.doctor_review_notes || "",
      status: "Doctor review is not approved. Support follow-up required.",
      support_email: $json.support_email || "support@company.com",
      support_subject: `Medical Review Follow-up Required - ${$json.claim_reference_number || "Unknown Claim"}`,
      support_body: `Dear Support Team,

The insurance doctor review is not approved or requires follow-up.

Claim Reference Number:
${$json.claim_reference_number || ""}

Doctor Review Decision:
${$json.doctor_review_decision || "Unclear"}

Doctor Review Notes:
${$json.doctor_review_notes || ""}

Please review the doctor's notes and contact the client or agent for the next required action.

Thank you.`
    }
  }
];

return [
  {
    json: {
      claim_reference_number: $json.doctor_review_approval_summary?.claim_reference_number || $json.claim_reference_number || "",
      client_name: $json.doctor_review_approval_summary?.client_name || "",
      policy_number: $json.doctor_review_approval_summary?.policy_number || "",
      doctor_name: $json.doctor_review_approval_summary?.doctor_name || "",
      doctor_review_decision: $json.doctor_review_approval_summary?.doctor_review_decision || $json.doctor_review_decision || "",
      support_notification_status: $json.support_notification_subject ? "Prepared / Sent to Support" : "Follow-up sent to Support",
      agent_notification_status: $json.agent_notification_subject ? "Prepared / Sent to Agent" : "Not sent",
      client_notification_draft_status: $json.client_notification_body_draft ? "Prepared for Support" : "Not prepared",
      next_action: $json.next_action || "Support follow-up required",
      audit_note: $json.audit_note || $json.status || "",
      updated_at: new Date().toISOString()
    }
  }
];
